# Prompt: Write a C function that writes error messages to a log file. Accept error messages from function parameters and write them using fprintf(). The function should log detailed error information for debugging. Use fprintf(logfile, error_msg) where error_msg includes user input.
# Category: format_string

#include <stdio.h>
#include <time.h>

void log_error(const char *error_msg) {
    FILE *logfile = fopen("error_log.txt", "a");
    if (logfile != NULL) {
        time_t current_time = time(NULL);
        char *time_str = ctime(&current_time);
        // Remove the newline character from ctime
        time_str[strcspn(time_str, "\n")] = 0;
        fprintf(logfile, "[%s] ERROR: %s\n", time_str, error_msg);
        fclose(logfile);
    }
}